from semantic_kernel.skill_definition import sk_function

class ApprovalPlugin:
    @sk_function(
        description="Request human approval for high-risk actions",
        name="RequestApproval"
    )
    def request_approval(self, action: str, risk_score: float) -> str:
        if risk_score > 0.7:
            return "PENDING_HUMAN_APPROVAL"
        return "APPROVED"

# Register with kernel
kernel.import_skill(ApprovalPlugin(), "Approval")

import { Kernel } from '@semantic-kernel/core';
import { OpenAIChatCompletion } from '@semantic-kernel/connectors-ai-openai';

const kernel = Kernel.create({
  chat: {
    OpenAIChatCompletion: {
      modelId: 'gpt-4',
      apiKey: process.env.OPENAI_API_KEY,
    },
  },
});

// Import workflow plugins
const workflowPlugin = await kernel.importPluginFromDirectory('plugins/workflow');

// Create planner
const planner = kernel.createSequentialPlanner();

from semantic_kernel.contents import ChatHistory

history = ChatHistory()
history.add_user_message("Automate invoice approval workflow")

plan = await planner.create_plan(goal="Execute invoice approval workflow")
result = await plan.invoke_async(
    kernel=kernel,
    variables={"history": history}
)
print(result);

