import vex

from semantic_kernel import KernelFunction

# Initialize Vex client
vex_client = vex.Client(api_key="your-vex-key")

@vex.function(
    name="workflow_step_verify",
    spec={
        "action_correctness": True,
        "permission_validation": True,
        "idempotency": True
    }
)
def verify_workflow_result(function_result: str, context: dict) -> dict:
    """Vex verification for Semantic Kernel function results"""
    return vex_client.verify({
        "input": function_result,
        "metadata": context,
        "policy": "workflow-medium-risk"
    })

# Register as kernel filter
def kernel_result_filter(result: KernelFunction):
    verified = verify_workflow_result(result.value, result.variables)
    if not verified['pass']:
        raise ValueError(f"Vex verification failed: {verified['reason']}")
    return result

import { Vex } from 'vex-sdk';

const vex = new Vex({ apiKey: 'your-vex-key' });

kernel.registerFunctionInvocationMiddleware(async (context, next) => {
  const result = await next();

  const verification = await vex.verify({
    input: result.value,
    metadata: {
      functionName: context.function.name,
      workflowStep: context.variables.step
    },
    policy: {
      actionCorrectness: true,
      permissionValidation: true,
      idempotency: true,
      rollbackCapability: true
    }
  });

  if (!verification.pass) {
    throw new Error(`Vex failed: ${verification.reason}`);
  }

  return result;
});

async def validate_execution_plan(plan: SequentialPlan, kernel: Kernel):
    plan_steps = [step.name for step in plan._steps]

    vex_result = vex_client.verify({
        "input": {
            "plan_steps": plan_steps,
            "workflow_type": "automation"
        },
        "policy": {
            "plan_validity": True,
            "sequence_correctness": True,
            "dependency_check": True
        }
    })

    if not vex_result['pass']:
        raise ValueError(f"Invalid plan: {vex_result['reason']}")

    return plan

# Use before invocation
plan = await planner.create_plan(goal)
